const fs = require('fs');
const path = require('path');

const files = {
  "src/app/about/page.tsx": ``,
  "src/app/contact/page.tsx": ``,
  "src/app/api/contact/route.ts": ``,
  "src/app/api/leads/route.ts": ``,
  "src/app/api/quote-requests/route.ts": ``,
  "supabase/migrations/010_contact_messages.sql": ``,
};

Object.entries(files).forEach(([filePath, b64]) => {
  const fullPath = path.join(process.cwd(), filePath);
  const dir = path.dirname(fullPath);
  fs.mkdirSync(dir, { recursive: true });
  const content = Buffer.from(b64, 'base64').toString('utf-8');
  fs.writeFileSync(fullPath, content, 'utf-8');
  console.log('Wrote:', filePath);
});

console.log('\n✅ Patch v21 applied — About page, Contact page, Email notifications');
console.log('\n📧 All leads, quotes, and contact messages now notify ryan@baadigi.com');
console.log('\n⚠️  Run the migration in Supabase SQL Editor:');
console.log('    File: supabase/migrations/010_contact_messages.sql');
console.log('\nThen: git add -A && git commit -m "v21: about + contact pages, email notifications" && git push');
